class Solution {
    public int maxValue(int n, int index, int maxSum) {
        int left = index, right = n - index - 1;
        int low = 1, high = maxSum;
        while (low < high) {
            int mid = low + (high - low + 1) / 2;
            if ((mid - 1) * mid / 2 <= maxSum - mid - (mid - 1) * right) {
                low = mid;
            } else {
                high = mid - 1;
            }
        }
        return low;
    }
}
